var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"그만두시죠, 이수연님.","JPN":"おやめください、カナミ・キズナ殿。","ENG":"That's enough, ma'am.","TWN":"請住手，李秀妍小姐。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신들......?","JPN":"あなたたちは……？","ENG":"You guys?","TWN":"你們是……？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하하, 펜릴 전대의 말괄량이 에이스 아니십니까.","JPN":"ハハッ、フェンリル戦隊のお転婆エース殿ではありませんか。","ENG":"Hah hah, look who's here. The tomboy ace of the Fenrir Division.","TWN":"哈哈，這不是芬里爾戰隊的潑辣王牌嗎。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"못 보던 사이에 많이 변하셨네요. 그래도 저희 대장을 괴롭히시면 안 되죠.","JPN":"しばらく見ない間に立派になられましたね。\\nしかし、うちの隊長をいじめてもらっては困りますぞ。","ENG":"You sure changed a lot since the last time we saw you. That doesn't mean you can bully our Commander around.","TWN":"好久沒看到妳了，妳變了好多啊。但就算這樣，妳也不可以為難我們隊長啊。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"예고르......? 발레리......?","JPN":"イェゴール……？　ヴァレリー……？","ENG":"Yegor? Valeriy?","TWN":"伊高爾……？瓦萊里……？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"게다가......","JPN":"それに……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"한숨 푹 자고 일어난 것 같은데, 오랜만이라고 인사하려니 이상하네.","JPN":"どうやらぐっすり眠っちゃってたみたいだけど、\\n久しぶりって挨拶するのも何だか変な気がするわ。","ENG":"I feel like I just got up from a nap, so it feels weird to say long time no see.","TWN":"我好像只是睡了一下而已，說好久不見感覺真奇怪。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그동안 고생 많았지, 류드밀라?","JPN":"今まで一人で大変だったでしょう？　\\nよく頑張ったわね、リュドミラちゃん。","ENG":"I bet you've been through a heck of a ride, huh, Lyudmila?","TWN":"這段時間妳一定吃了不少苦吧，盧德米拉？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스까지......?","JPN":"アレックスまで……？","ENG":"Alex too?","TWN":"連雅蕾克絲都……？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신들, 어떻게 여기에 나와 있는 겁니까?","JPN":"あなたたち、どうやってここに出られたのですか？","ENG":"How did you guys get out here?","TWN":"你們，怎麼都出來了？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"그간의 사정은 관리자님께 모두 들었습니다.","JPN":"今までの事情はすべて管理者殿からご説明いただきました。","ENG":"The Administrator told us about everything.","TWN":"這段時間的事情，我們都聽管理者大人說了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"전대장님이 그림자로 바뀌었을지도 모른다는 추측까지 전부요.","JPN":"戦隊長がシャドウに変異したかもしれないという\\n推測も含め、すべてをです。","ENG":"Even about the speculation that the Commander here may have turned into a Shadow.","TWN":"包括隊長有可能已經變成暗影了這件事。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그걸 알면서도...... 그녀를 당신들의 대장으로 인정한다는 겁니까?","JPN":"それをわかっていながら……\\n彼女をあなた方の隊長と認めるのですか？","ENG":"You know that already... and you still choose to accept her as your Commander?","TWN":"既然你們都知道了……還要承認她是你們的隊長嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"안 될 것 있습니까?","JPN":"何か問題でも？","ENG":"Sure, why not?","TWN":"有什麼不可以的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"이수연 님은 잘 모르실 수도 있겠지만, 저희 전대원은 대부분 일반인입니다.","JPN":"カナミ・キズナ殿はご存知ないかもしれませんが、\\n我が戦隊はほとんどが一般人です。","ENG":"You may not know this, but most of the division's members are regular folks.","TWN":"李秀妍小姐可能不知道，但我們的隊員大部分都是普通人。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"누구든 침식 증후군에 시달릴 수 있다는 것쯤은 각오하고 있어요.","JPN":"誰もが侵食症候群に冒される可能性がある。それくらい\\n覚悟の上なのです。","ENG":"We know in the back of our minds that any one of us could suffer from Corruption syndrome.","TWN":"我們早就做好了隨時患上侵蝕症候群的心理準備。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그래서 저희는 마지막까지 옆에 있는 동료를 믿어 주기로 했습니다.","JPN":"そして我々は最後の瞬間まで隣にいる仲間を信じると決めました。","ENG":"So we've decided to put our trust in whoever sticks with us till the very end.","TWN":"因此，我們決定直到最後，都要相信身邊的同伴。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그래야만 포기하지 않고 변해 가는 자신과 싸울 수 있을 테니까요.","JPN":"だからこそ、変異していく己自身に負けることなく、\\n諦めずに戦えるのです。","ENG":"That's the only way they can continue to fight against their ever-changing self.","TWN":"只有這樣，我們才能與不斷變異的自己戰鬥下去。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 바보 같은 소리를......","JPN":"何をバカなことを……","ENG":"Don't be ridiculous...","TWN":"說什麼傻話……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"인간이 변이한 침식체도 침식체일 뿐입니다. 결국 본질은......","JPN":"人間が変異した侵食体も結局は侵食体です。\\n本質において違いは……","ENG":"A C.O. is a C.O., even if it was originally a human. Its nature is—","TWN":"即使是由人類變異的侵蝕體，也就是個侵蝕體而已，本質上是……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"본질이란 게 뭔데?","JPN":"本質ってなぁに？","ENG":"What exactly is that nature?","TWN":"所謂的本質又是什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 복제인간이지만, 나와 같은 모델의 복제인간이 모두 알렉스인 건 아냐.","JPN":"私はクローン人間よ。でも、私と同じモデルのクローンが\\n全員同じアレックスってわけじゃないわ。","ENG":"I'm a clone, but that doesn't mean all the other clones are Alex.","TWN":"我雖然是克隆人，但有我這樣形體的克隆人卻都不是雅蕾克絲。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"결국 그 사람의 의지와 행동이 본질 아니겠어?","JPN":"結局は個々の意志と行動を本質と捉えるべきなんじゃないかしら？","ENG":"Doesn't it ultimately come down to each individual's will and actions?","TWN":"最終，決定一個人本質的，不就是他的意志和行動嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 에이스께서 보시기엔 어때?","JPN":"管理局のエース様の感想はどう？","ENG":"What does the ace of the Administration think?","TWN":"管理局王牌是怎麼看的？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저 애가 류드밀라가 아닌 것 같아?","JPN":"あの子はリュドミラじゃないと言い切れるの？","ENG":"Do you really think she's not Lyudmila?","TWN":"妳認為她不是盧德米拉嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다들...... 옹호해 줘서 고맙다.","JPN":"みんな……擁護感謝する。","ENG":"Everyone... Thank you for defending me.","TWN":"大家……謝謝你們擁護我。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 나는...... 그림자란 말이다......","JPN":"だが私は……やはりシャドウなのだ……","ENG":"But I... I'm a Shadow...","TWN":"但是……我是暗影……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이미 침식체로 변해 버린 이상...... 언제 이성을 잃고 너희를 공격할지 모른다.","JPN":"すでに侵食体と化してしまった以上……いつ理性を失くし、\\nお前たちを攻撃してしまうかわからないんだ。","ENG":"Now that I've turned into a Corrupted Object... there's no telling when I'll lose my mind and begin to attack you.","TWN":"我已經變成了侵蝕體……隨時都有可能發狂攻擊你們。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그게 무슨 상관입니까. 전대장님이 절 구해 주신 것만 다섯 번이 넘습니다.","JPN":"どうってことありませんよ。私が戦隊長に助けていただいた\\n回数は数えきれません。","ENG":"Who cares? You already saved my life a half dozen times.","TWN":"那又有什麼關係，隊長已經救我們好幾次了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"한 번 정도는 충분히 받아 드려야죠.","JPN":"一度や二度くらい、喜んで命を張らせていただきますよ。","ENG":"I think I can cut you some slack if you attack me once.","TWN":"被你攻擊一次也算不了什麼。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"여기, 동료들이 있는 메이즈 전대야말로 저희들이 있어야 할 곳입니다.","JPN":"仲間たちがいるこのメイズ戦隊こそが我々の居場所です。","ENG":"This is exactly where we're supposed to be. Here with the rest of the Maze Division.","TWN":"在這裡，有同伴在的梅茲戰隊才是我們的歸宿。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"그리고 전대장님 없이 메이즈 전대는 성립하지 않아요.","JPN":"そして、戦隊長なくしてメイズ戦隊は成り立ちません。","ENG":"And Maze Division wouldn't exist without you.","TWN":"如果沒有隊長，那就沒有梅茲戰隊。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"다들 잘 들었지. 지금 한 말에 틀린 부분 있나?","JPN":"つまりはそういうことだ。みんな、異存はないな？","ENG":"Well, you heard that. Does anyone object to what we said?","TWN":"大家都聽到了吧。剛剛說的話，有沒有什麼不對的地方？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너희들......","JPN":"お前たち……","ENG":"You guys...","TWN":"你們……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당연한 일에 괜히 감격하지 마, 류드밀라.","JPN":"そんなに感激しないで、リュドミラちゃん。\\nこんなの当たり前のことなんだから。","ENG":"Don't get so choked up over it, Lyudmila. We're only doing what's right.","TWN":"不要因為這種理所當然的事情感動啦，盧德米拉。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗, 울고 싶으면 머리라도 쓰다듬어 줄까?","JPN":"ふふっ、今にも泣きそうな顔しちゃって。\\n頭なでなでしてあげましょ～か？","ENG":"Heh heh, if you want to cry, I can pat you on the head.","TWN":"呵呵，想哭的話，要不要我摸摸妳的頭啊？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"잘했어요, 잘했어~ 하고.","JPN":"よちよち、よくできまちたね～ってね。","ENG":"And I'll tell you that you're a good girl and everything.","TWN":"好棒喔，好棒～乖。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대, 대원들 앞이다! 자제하도록!","JPN":"た、隊員たちの前だぞ！　自重してくれ！","ENG":"The troops are watching! E-exercise some restraint!","TWN":"隊、隊員們都在看啦！快住手！"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 여전하네.","JPN":"ふふっ。その反応も相変わらずね。","ENG":"Heh heh. You haven't changed at all.","TWN":"呵呵，還是老樣子。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그리고 너 혼자 책임지게 할 리 없잖아.","JPN":"あなた一人に責任を負わせたりしないわ。","ENG":"You know we won't let you just take on the full weight of responsibility.","TWN":"還有，這不是妳一個人的責任。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"20년이나 지각했는데, 남은 시간이라도 바짝 템포를 올려야 하지 않겠어?","JPN":"20年も遅刻しちゃったんだし、せめて残された時間は\\nハイテンポで行かなくちゃね。","ENG":"We're 20 years too late. The least we can do is crank up the tempo the last minute.","TWN":"我們都遲到20年了，剩下的時間可得加快腳步才行啊？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스, 그 말은......","JPN":"アレックス、お前は……","ENG":"Alex, you mean...","TWN":"雅蕾克絲，你的意思是……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마, 도플갱어들과 싸울 작정인가요?","JPN":"まさか、ドッペルゲンガーたちと戦うつもりですか？","ENG":"Are you planning to fight the Doppelgangers?","TWN":"該不會要跟二重身戰鬥吧？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신들은 침식 증후군 말기 환자입니다. 안정을 취해도 모자랄 판에 전투를 하게 되면......","JPN":"あなたたちは侵食症候群の末期患者です。\\n安静にしてもらっても不安だというのに、戦闘なんかしてしまったら……","ENG":"All of you are suffering from late-stage Corruption syndrome. If anything, you should be resting, not fighting...","TWN":"你們是侵蝕症候群末期患者。你們必須安神養心，不可以戰鬥……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"어차피 바뀌는 건 없잖아?","JPN":"結局、行き着く先は同じでしょう？","ENG":"It's not going to make a difference though, you know?","TWN":"反正事情都不會改變吧？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"결국 침식체가 되어 버릴 거라면, 아직 인간으로 남아 있을 때 류드밀라와 함께 싸우겠어.","JPN":"どうせ侵食体になるんだったらまだ人間でいられる間に、\\n戦隊長と肩を並べて戦いたいの。","ENG":"If we're going to end up becoming C.O.s anyway, we might as well as fight by Lyudmila's side while we still can.","TWN":"既然我們都會變成侵蝕體，那還不如趁現在還是人類的時候，和盧德米拉一起戰鬥。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼 혹시 모르잖아?","JPN":"そうすれば私や他の子どもたちにも、\\nもしかしたら奇跡が起きるかもしれないでしょう？","ENG":"You never know.","TWN":"那之後的事情誰又能知道呢？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"나나, 다른 애들이 침식체로 변해도 류드밀라처럼 긍지라는 걸 잊지 않을지.","JPN":"たとえ侵食体に変わってしまっても、リュドミラちゃんのように\\n誇りってものを失くさずに済むかもしれないじゃない。","ENG":"Even if we all turn into C.O.s, maybe we'll get to retain our honor, like Lyudmila here.","TWN":"說不定我和其他隊員變成侵蝕體後，都會像盧德米拉一樣，不會忘記梅茲戰隊的驕傲。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스......","JPN":"アレックス……","ENG":"Alex...","TWN":"雅蕾克絲……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 역시 이런 낯뜨거운 대사는 나랑 안 맞네.","JPN":"ふふっ。やっぱりこういう気恥ずかしい台詞は私向きじゃないわ。","ENG":"Heh heh. I knew those lines would sound cheesy when I said it.","TWN":"呵呵，我果然不適合這種肉麻的台詞。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"자, 혼자 싸우면서 고생했던 만큼은 갚아 줘야지?","JPN":"さて、たった一人でさんざん苦労させられたのよね？","ENG":"Now, it's time to pay you back for making you fight all alone.","TWN":"來吧，妳一個人戰鬥時所受的痛苦，是時候該還回去了！"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이번엔 우리가 먼저 공격할 차례야.","JPN":"これからは私たちが反撃する番だわ。","ENG":"We're going to strike them first this time.","TWN":"這次輪到我們率先發動攻擊了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"준비는 이미 마쳤습니다. 전대장님.","JPN":"準備はすでに完了しています。戦隊長殿。","ENG":"All the preparations are ready, Commander.","TWN":"已經準備完畢了，隊長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"게으름 피운 만큼 열심히 하겠습니다! 명령만 내려 주십시오!","JPN":"寝坊した分、一生懸命働きます！　何なりとご命令を！","ENG":"We'll make up for all the slacking off! Just give us your orders!","TWN":"我會像我偷懶的時候一樣努力的！儘管下命令吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알겠다.","JPN":"承知した。","ENG":"Understood.","TWN":"知道了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전 대원! 역경을 견디고 전선으로 복귀해 준 것에 대해 감사를 표한다!","JPN":"全隊員に告げる！　逆境に耐え抜き、\\n戦線に復帰してくれたことに心より感謝する！","ENG":"Attention, all troops! You have my sincerest thanks for returning to the front lines despite the challenging circumstances!","TWN":"全體隊員！我為你們克服絕境，回到戰線表達感謝之意！"},"stage":{"bg":"SS_ADMIN_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"적은 우리를 본따 만들어진 도플갱어 타입 침식체 군집!","JPN":"敵は我々を象って造られたドッペルゲンガータイプ侵食体の群集！","ENG":"Our enemy is a cluster of Doppelganger-type C.O.s mimicking us!","TWN":"敵人是仿照我們模樣，誕生的二重身型侵蝕體群！"},"stage":{"bg":"SS_ADMIN_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리국과 세계를 위해, 그리고 대원들 스스로를 위해 적을 섬멸하라!","JPN":"管理局と世界のために、そして各員自らのために、敵を殲滅せよ！","ENG":"Exterminate the enemy for the Administration, for the world, and for yourselves!","TWN":"為了管理局和這個世界，還有為了我們隊員自己，殲滅敵人吧！"},"stage":{"bg":"SS_ADMIN_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"메이즈 전대, 전투 준비!","JPN":"メイズ戦隊、戦闘用意！","ENG":"Maze Division, prepare for battle!","TWN":"梅茲戰隊，準備戰鬥！"},"stage":{"bg":"SS_ADMIN_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"적들에게 강철의 눈보라를 선사하도록!","JPN":"鋼鉄の吹雪をお見舞いしてやれ！","ENG":"Bring a blizzard of steel upon the enemy!","TWN":"讓敵人嘗嘗鋼鐵的暴風雪吧！"},"stage":{"bg":"SS_ADMIN_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"언제봐도 대단한 친구들이군. 그렇지 않나.","JPN":"いつ見ても頼もしい連中だ。そう思わないかね？","ENG":"They never fail to impress me. Wouldn't you agree?","TWN":"不管什麼時候看，她們都是一群了不起的朋友啊。妳說對吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신은...... 이런 광경을 많이 봐 왔겠군요.","JPN":"あなたは……こんな光景を何度も目にしてきたんでしょうね。","ENG":"You... probably saw this sort of stuff quite often.","TWN":"這樣的場景……你應該見過很多次吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네.","JPN":"ああ、そうさ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......아주 많이 봤었지.","JPN":"……幾度となく、な。","ENG":"All too often...","TWN":"……見過很多次了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};